type Screen = 'landing' | 'projects' | 'create' | 'workbench' | 'settings'
type Tab = 'gantt'|'network'|'wbs'|'process'|'library'|'resource'|'review'|'milestone'|'report'
type AgentStepState={key:'parse'|'match'|'review'|'confirm';label:string;description:string;status:'pending'|'running'|'done'|'error';detail?:string}
const INITIAL_AGENT_STEPS:AgentStepState[]=[
  {key:'parse',label:'条件解析 Agent',description:'识别项目类型、规模、日期和空间层级',status:'pending'},
  {key:'match',label:'模板匹配 Agent',description:'选择专业模板包并提出候选工序',status:'pending'},
  {key:'review',label:'依赖审查 Agent',description:'生成试排计划并检查工期、逻辑和资源风险',status:'pending'},
  {key:'confirm',label:'确认输出 Agent',description:'由用户确认候选模板后写入模板库',status:'pending'},
]
const SETTINGS_KEY='construction_schedule_ai_settings'
const PROJECT_KEY='construction_schedule_project_v1'
const TASKS_KEY='construction_schedule_tasks_v1'
const BASELINES_KEY='construction_schedule_baselines_v1'
const CURRENT_PROJECT_KEY='construction_schedule_current_project_id'
const CUSTOM_TEMPLATES_KEY='construction_schedule_custom_templates_v1'

const readJson=<T,>(key:string,fallback:T):T=>{try{return JSON.parse(localStorage.getItem(key)??'') as T}catch{return fallback}}
const mergeTemplateLibraries=(server:TaskTemplate[],local:TaskTemplate[])=>{
  const byKey=new Map<string,TaskTemplate>()
  ;[...server,...local].forEach(template=>{
    const key=template.id||`${template.projectType??'通用'}:${template.name}`
    const previous=byKey.get(key)
    const newer=!previous||String(template.updatedAt??'')>=String(previous.updatedAt??'')
    if(newer)byKey.set(key,{...template,isCustom:true})
  })
  return [...byKey.values()]
}

export default function App(){
  const query=new URLSearchParams(location.search).get('landing')
  const storedProject=readJson<ProjectData>(PROJECT_KEY,DEFAULT_PROJECT)
  const savedProject:ProjectData={...DEFAULT_PROJECT,...storedProject,calendar:storedProject.calendar??DEFAULT_PROJECT.calendar}
  const savedTasks=readJson<Task[]>(TASKS_KEY,[])
  const [screen,setScreen]=useState<Screen>(query==='new'?'create':query==='demo'?'workbench':localStorage.getItem(CURRENT_PROJECT_KEY)?'workbench':'landing')
  const [project,setProject]=useState<ProjectData>(savedProject)
  const [tasks,setTasks]=useState<Task[]>(query==='demo'?generateSchedule(DEFAULT_PROJECT,BASE_TEMPLATES):savedTasks)
  const [settings,setSettings]=useState<AiSettings|null>(null)
  const [auth,setAuth]=useState<AuthStatus>({authenticated:false,user:null})
  const [authOpen,setAuthOpen]=useState(false)
  const [baselines,setBaselines]=useState<PlanBaseline[]>(()=>readJson<PlanBaseline[]>(BASELINES_KEY,[]))
  const [currentProjectId,setCurrentProjectId]=useState(()=>localStorage.getItem(CURRENT_PROJECT_KEY)??'')
  const [customTemplates,setCustomTemplates]=useState<TaskTemplate[]>(()=>readJson<TaskTemplate[]>(CUSTOM_TEMPLATES_KEY,[]))
  const [templateSyncStatus,setTemplateSyncStatus]=useState('模板库等待同步')
  const [history,setHistory]=useState<Task[][]>([]),[future,setFuture]=useState<Task[][]>([])

  const navigate=(next:Screen,landing?:'new'|'demo')=>{setScreen(next);window.history.replaceState(null,'',landing?`/?landing=${landing}`:'/')}
  const newProjectId=()=>`P-${globalThis.crypto?.randomUUID?.()??Date.now()}`
  const persistLocal=(nextProject:ProjectData,nextTasks:Task[],nextBaselines:PlanBaseline[])=>{localStorage.setItem(PROJECT_KEY,JSON.stringify(nextProject));localStorage.setItem(TASKS_KEY,JSON.stringify(nextTasks));localStorage.setItem(BASELINES_KEY,JSON.stringify(nextBaselines))}
  const generate=(data:ProjectData)=>{setCurrentProjectId(newProjectId());setProject(data);setTasks(generateSchedule(data,templatesForProject(data,customTemplates)));setBaselines([]);setHistory([]);setFuture([]);navigate('workbench')}
  const updateCustomTemplates=(next:TaskTemplate[])=>{setCustomTemplates(next);localStorage.setItem(CUSTOM_TEMPLATES_KEY,JSON.stringify(next));setTemplateSyncStatus('正在保存到后端模板库…');saveServerCustomTemplates(next).then(saved=>{setCustomTemplates(saved);localStorage.setItem(CUSTOM_TEMPLATES_KEY,JSON.stringify(saved));setTemplateSyncStatus(`已同步 ${saved.length} 项自定义模板到后端`)}).catch(error=>setTemplateSyncStatus(error instanceof Error?`后端模板库同步失败：${error.message}`:'后端模板库同步失败，已保留本地副本'))}
  const mutate=(fn:(items:Task[])=>Task[])=>{setHistory(h=>[...h.slice(-29),tasks]);setFuture([]);setTasks(fn(tasks))}
  const undo=()=>{const prev=history.at(-1);if(!prev)return;setFuture(f=>[tasks,...f]);setTasks(prev);setHistory(h=>h.slice(0,-1))}
  const redo=()=>{const next=future[0];if(!next)return;setHistory(h=>[...h,tasks]);setTasks(next);setFuture(f=>f.slice(1))}
  const save=async()=>{const id=currentProjectId||newProjectId();persistLocal(project,tasks,baselines);localStorage.setItem(CURRENT_PROJECT_KEY,id);setCurrentProjectId(id);await saveProjectToServer(id,{project,tasks,baselines,customTemplates})}
  const logout=async()=>{try{setAuth(await logoutAccount())}catch{setAuth({authenticated:false,user:null})}}
  const updateBaselines=(next:PlanBaseline[])=>{setBaselines(next);localStorage.setItem(BASELINES_KEY,JSON.stringify(next))}
  const restoreData=(data:{project:ProjectData;tasks:Task[];baselines?:PlanBaseline[];customTemplates?:TaskTemplate[]})=>{setProject({...DEFAULT_PROJECT,...data.project});setTasks(data.tasks);updateBaselines(data.baselines??[]);if(data.customTemplates)updateCustomTemplates(data.customTemplates);setHistory([]);setFuture([])}
  const openSaved=async(id:string)=>{const record=await loadSavedProject(id);setCurrentProjectId(id);localStorage.setItem(CURRENT_PROJECT_KEY,id);restoreData(record);persistLocal(record.project,record.tasks,record.baselines);navigate('workbench')}
  const removeSaved=async(id:string)=>{await deleteSavedProject(id);if(id===currentProjectId){setCurrentProjectId('');localStorage.removeItem(CURRENT_PROJECT_KEY)}}
  useEffect(()=>{if(query==='demo'||!currentProjectId)return;loadSavedProject(currentProjectId).then(record=>{restoreData(record);persistLocal(record.project,record.tasks,record.baselines)}).catch(()=>{})},[])
  useEffect(()=>{loadAuthStatus().then(setAuth).catch(()=>setAuth({authenticated:false,user:null}))},[])
  useEffect(()=>{const local=readJson<TaskTemplate[]>(CUSTOM_TEMPLATES_KEY,[]);setTemplateSyncStatus('正在加载后端模板库…');loadServerCustomTemplates().then(server=>{const merged=mergeTemplateLibraries(server,local);setCustomTemplates(merged);localStorage.setItem(CUSTOM_TEMPLATES_KEY,JSON.stringify(merged));setTemplateSyncStatus(`已加载 ${merged.length} 项后端自定义模板`);if(merged.length!==server.length)saveServerCustomTemplates(merged).catch(()=>{})}).catch(error=>setTemplateSyncStatus(error instanceof Error?`后端模板库加载失败：${error.message}`:'后端模板库加载失败，使用本地模板'))},[auth.authenticated,auth.user?.id])
  useEffect(()=>{const legacy=readJson<AiSettings|null>(SETTINGS_KEY,null);loadServerAiConfig().then(async config=>{if(!config.configured&&legacy?.apiKey){const migrated=await saveServerAiConfig({provider:legacy.provider,model:legacy.model,apiKey:legacy.apiKey});localStorage.removeItem(SETTINGS_KEY);setSettings(migrated)}else{if(config.configured)localStorage.removeItem(SETTINGS_KEY);setSettings(config.configured?config:null)}}).catch(()=>setSettings(legacy))},[])

  if(screen==='landing')return <><Landing auth={auth} hasSaved={tasks.length>0} onAuth={()=>setAuthOpen(true)} onLogout={logout} onResume={()=>navigate('workbench')} onLibrary={()=>navigate('projects')} onStart={()=>navigate('create','new')} onDemo={()=>{setCurrentProjectId('');setProject(DEFAULT_PROJECT);setTasks(generateSchedule(DEFAULT_PROJECT,BASE_TEMPLATES));navigate('workbench','demo')}}/><AuthDialog open={authOpen} auth={auth} onClose={()=>setAuthOpen(false)} onChange={setAuth}/></>
  return <><div className="application"><SideNav auth={auth} screen={screen} hasTasks={tasks.length>0} onAuth={()=>setAuthOpen(true)} onLogout={logout} onGo={navigate} onDemo={()=>{setCurrentProjectId('');setProject(DEFAULT_PROJECT);setTasks(generateSchedule(DEFAULT_PROJECT,BASE_TEMPLATES));navigate('workbench','demo')}}/>
    <div className="app-content">
      {screen==='projects'&&<ProjectLibrary auth={auth} onAuth={()=>setAuthOpen(true)} currentId={currentProjectId} onOpen={openSaved} onDelete={removeSaved} onNew={()=>navigate('create','new')}/>} 
      {screen==='create'&&<CreatePage initial={project} settings={settings} customTemplates={customTemplates} onCustomTemplatesChange={updateCustomTemplates} onGenerate={generate} onDemo={()=>{setProject(DEFAULT_PROJECT);setTasks(generateSchedule(DEFAULT_PROJECT,BASE_TEMPLATES));navigate('workbench','demo')}} onSettings={()=>navigate('settings')}/>} 
      {screen==='settings'&&<SettingsPage value={settings} onChange={setSettings} onBack={()=>navigate(tasks.length?'workbench':'create')}/>} 
      {screen==='workbench'&&<Workbench project={project} tasks={tasks} settings={settings} baselines={baselines} templates={templatesForProject(project,customTemplates)} customTemplates={customTemplates} templateSyncStatus={templateSyncStatus} onCustomTemplatesChange={updateCustomTemplates} onProjectChange={setProject} onBaselinesChange={updateBaselines} onRestoreData={restoreData} onMutate={mutate} onLibrary={()=>navigate('projects')} onNew={()=>navigate('create','new')} onSettings={()=>navigate('settings')} onSave={save} onUndo={undo} onRedo={redo} canUndo={history.length>0} canRedo={future.length>0}/>} 
    </div>
  </div><AuthDialog open={authOpen} auth={auth} onClose={()=>setAuthOpen(false)} onChange={setAuth}/></>
}

