  const importFile=async(file?:File)=>{if(!file)return;try{const data=JSON.parse(await file.text()) as {project?:ProjectData;tasks?:Task[];baselines?:PlanBaseline[];customTemplates?:TaskTemplate[]};if(!data.project||!Array.isArray(data.tasks)||!data.tasks.length)throw new Error('备份文件缺少 project 或 tasks');onRestore({project:data.project,tasks:data.tasks,baselines:Array.isArray(data.baselines)?data.baselines:[]});if(Array.isArray(data.customTemplates))onCustomTemplatesChange(data.customTemplates);setStatus(`已恢复 ${data.tasks.length} 项任务和 ${data.customTemplates?.length??0} 项自定义模板。`)}catch(e){setStatus(e instanceof Error?`导入失败：${e.message}`:'导入失败')}}
  const useForCompare=(baseline:PlanBaseline)=>{onBaselinesChange([...baselines.filter(b=>b.id!==baseline.id),baseline]);setStatus(`已切换为「${baseline.name}」进行对比。`)}
  const restoreBaseline=(baseline:PlanBaseline)=>{const byId=new Map(baseline.tasks.map(t=>[t.id,t]));onRestore({project,tasks:tasks.map(t=>{const base=byId.get(t.id);return base?{...t,startDate:base.startDate,endDate:base.endDate,duration:base.duration,source:'手动修改'}:t}),baselines});setStatus(`已恢复「${baseline.name}」的计划日期。`)}
  const exportExcel=async()=>{try{setStatus('正在生成 Excel 工作簿…');await exportProjectExcel(project,tasks,baselines);setStatus('Excel 工作簿已生成，包含项目概览、WBS、资源负荷、风险审查和计划基准。')}catch(e){setStatus(e instanceof Error?`Excel 导出失败：${e.message}`:'Excel 导出失败')}}
  return <div className="modal-backdrop" onMouseDown={e=>{if(e.target===e.currentTarget)onClose()}}><section className="data-manager"><header><div><h2>项目数据与计划基准</h2><p>保存基准用于偏差分析，JSON 用于跨浏览器备份和恢复。</p></div><button aria-label="关闭数据管理" onClick={onClose}>×</button></header><div className="data-actions"><article><h3>创建计划基准</h3><p>冻结当前任务日期，之后在横道图中显示灰色基准条和完成偏差。</p><div><input aria-label="基准名称" value={name} onChange={e=>setName(e.target.value)}/><button className="btn primary" onClick={createBaseline}>设为新基准</button></div></article><article><h3>导出与备份</h3><p>Excel 用于汇报；JSON 包含项目、任务、基准和自定义模板，可完整恢复。</p><div><button className="btn primary" onClick={exportExcel}>导出 Excel</button><button className="btn" onClick={()=>exportProjectJson(project,tasks,baselines,customTemplates)}>导出 JSON</button><button className="btn" onClick={()=>fileRef.current?.click()}>导入 JSON</button><input ref={fileRef} hidden type="file" accept="application/json,.json" onChange={e=>importFile(e.target.files?.[0])}/></div></article></div><div className="baseline-list"><div className="baseline-title"><h3>基准版本</h3><span>{baselines.length} 个</span></div>{baselines.length?baselines.map((b,i)=><div className="baseline-item" key={b.id}><span>{i===baselines.length-1?'当前对比':'历史'}</span><div><b>{b.name}</b><small>{new Date(b.createdAt).toLocaleString('zh-CN')} · {b.tasks.length} 项任务 · 完工 {b.tasks.at(-1)?.endDate}</small></div><div className="baseline-actions">{i!==baselines.length-1&&<button className="btn" onClick={()=>useForCompare(b)}>对比</button>}<button className="btn" onClick={()=>restoreBaseline(b)}>恢复</button><button className="btn danger" onClick={()=>onBaselinesChange(baselines.filter(x=>x.id!==b.id))}>删除</button></div></div>):<div className="empty">尚未创建计划基准。</div>}</div>{status&&<p className="data-status">{status}</p>}</section></div>
