function ProgressUpdater({project,tasks,onApply,onClose}:{project:ProjectData,tasks:Task[],onApply:(request:BatchProgressRequest)=>ProgressImpact,onClose:()=>void}){
  const [dataDate,setDataDate]=useState(project.dataDate??new Date().toISOString().slice(0,10)),[search,setSearch]=useState(''),[spaceFilter,setSpaceFilter]=useState('全部空间'),[selectedIds,setSelectedIds]=useState<string[]>([]),[status,setStatus]=useState<TaskStatus>('施工中'),[progress,setProgress]=useState(50),[setActualStart,setSetActualStart]=useState(true),[setActualEnd,setSetActualEnd]=useState(false),[impact,setImpact]=useState<ProgressImpact|null>(null)
  const spaceKey=project.spatialDimensions?.[0]?.name??'楼栋',spaces=[...new Set(tasks.map(t=>t.spacePath?.[spaceKey]??t.building).filter(Boolean) as string[])]
  const filtered=useMemo(()=>tasks.filter(t=>{const space=t.spacePath?.[spaceKey]??t.building;return(!search||`${t.wbsCode}${t.name}${t.discipline}`.includes(search))&&(spaceFilter==='全部空间'||!space||space===spaceFilter)}),[tasks,search,spaceFilter,spaceKey])
  const selected=new Set(selectedIds),allVisibleSelected=filtered.length>0&&filtered.every(t=>selected.has(t.id))
  const chooseStatus=(next:TaskStatus)=>{setStatus(next);if(next==='未开始')setProgress(0);else if(next==='施工中'&&progress===0)setProgress(50);else if(['监理验收通过','移交下道工序','资料闭合'].includes(next)){setProgress(100);setSetActualEnd(true)}else if(next==='实体完成')setProgress(Math.max(progress,90));else if(next==='自检完成')setProgress(Math.max(progress,95))}
  const apply=()=>{if(!selectedIds.length)return;setImpact(onApply({taskIds:selectedIds,dataDate,status,progress,setActualStart,setActualEnd}))}
  return <div className="modal-backdrop" onMouseDown={e=>{if(e.target===e.currentTarget)onClose()}}><section className="progress-updater"><header><div><h2>批量进度更新</h2><p>设置数据日期，批量更新状态、完成率与实际日期，并推演对关键节点的影响。</p></div><button aria-label="关闭进度更新" onClick={onClose}>×</button></header><div className="progress-toolbar"><TextField label="数据日期" type="date" value={dataDate} onChange={setDataDate}/><label>空间筛选<select value={spaceFilter} onChange={e=>setSpaceFilter(e.target.value)}><option>全部空间</option>{spaces.map(x=><option key={x}>{x}</option>)}</select></label><label>搜索任务<input placeholder="WBS、任务或专业" value={search} onChange={e=>setSearch(e.target.value)}/></label></div><div className="progress-layout"><section className="progress-task-list"><div className="progress-list-head"><label><input type="checkbox" checked={allVisibleSelected} onChange={e=>setSelectedIds(e.target.checked?[...new Set([...selectedIds,...filtered.map(t=>t.id)])]:selectedIds.filter(id=>!filtered.some(t=>t.id===id)))}/>选择当前筛选</label><span>已选 {selectedIds.length} / 显示 {filtered.length} / 全部 {tasks.length}</span></div><div className="progress-table"><div className="progress-row heading"><b></b><b>任务</b><b>计划完成</b><b>当前进度</b></div>{filtered.map(t=><label className={`progress-row ${t.progress<100&&t.endDate<dataDate?'overdue':''}`} key={t.id}><input type="checkbox" checked={selected.has(t.id)} onChange={e=>setSelectedIds(ids=>e.target.checked?[...ids,t.id]:ids.filter(id=>id!==t.id))}/><span><b>{t.wbsCode} {t.name}</b><small>{taskSpaceLabel(t)||t.discipline}</small></span><span>{t.endDate}{t.progress<100&&t.endDate<dataDate?<em>逾期</em>:null}</span><span>{t.status}<small>{t.progress}%</small></span></label>)}</div></section><aside className="progress-form"><h3>批量更新值</h3><SelectField label="任务状态" value={status} options={['未开始','施工中','实体完成','自检完成','监理验收通过','移交下道工序','资料闭合','暂停','延期']} onChange={v=>chooseStatus(v as TaskStatus)}/><NumberField label="完成进度" value={progress} onChange={v=>setProgress(Math.min(100,Math.max(0,v)))} suffix="%"/><div className="progress-checks"><label><input type="checkbox" checked={setActualStart} onChange={e=>setSetActualStart(e.target.checked)}/>未填写时，以数据日期作为实际开始</label><label><input type="checkbox" checked={setActualEnd} onChange={e=>setSetActualEnd(e.target.checked)}/>以数据日期作为实际完成</label></div><button className="btn primary block" disabled={!selectedIds.length||!dataDate} onClick={apply}>更新 {selectedIds.length} 项任务</button>{impact&&<div className="progress-impact"><h3>本次更新与偏差影响</h3><div><Metric label="更新任务" value={impact.updatedCount}/><Metric label="完成任务" value={impact.completedCount}/><Metric label="逾期未完" value={impact.overdueCount}/><Metric label="逾期关键" value={impact.overdueCriticalCount}/></div><p>{impact.affectedMilestones.length?`可能影响节点：${impact.affectedMilestones.join('、')}`:'未发现受影响的锁定里程碑。'}</p></div>}</aside></div></section></div>
}

function Gantt({tasks,baseline,selectedId,onSelect,onUpdateTask,onUpdateLogic,onRecalculate,logicMessage,onUndo,onRedo,canUndo,canRedo}:{tasks:Task[],baseline?:PlanBaseline,selectedId:string,onSelect:(id:string)=>void,onUpdateTask:(id:string,p:Partial<Task>)=>void,onUpdateLogic:(id:string,p:Partial<Task>)=>void,onRecalculate:()=>void,logicMessage:string,onUndo:()=>void,onRedo:()=>void,canUndo:boolean,canRedo:boolean}){
  type DragState={id:string;mode:'move'|'resize';startX:number;pxPerDay:number;startDate:string;endDate:string}
  const [scale,setScale]=useState<'day'|'week'|'month'>('month'),[drag,setDrag]=useState<DragState|null>(null),[preview,setPreview]=useState<{id:string;startDate:string;endDate:string}|null>(null)
  const previewRef=useRef(preview);previewRef.current=preview
  const start=tasks.reduce((m,t)=>t.startDate<m?t.startDate:m,tasks[0]?.startDate??''),end=tasks.reduce((m,t)=>t.endDate>m?t.endDate:m,tasks[0]?.endDate??''),selected=tasks.find(t=>t.id===selectedId)
  const pxPerDay=scale==='day'?18:scale==='week'?6:2.5,timelineWidth=Math.max(760,(dateDiff(start,end)+45)*pxPerDay),columns=`250px 55px ${timelineWidth}px`
  useEffect(()=>{if(!drag)return;const move=(event:PointerEvent)=>{const delta=Math.round((event.clientX-drag.startX)/drag.pxPerDay);if(drag.mode==='move')setPreview({id:drag.id,startDate:addDays(drag.startDate,delta),endDate:addDays(drag.endDate,delta)});else setPreview({id:drag.id,startDate:drag.startDate,endDate:addDays(drag.endDate,Math.max(1-dateDiff(drag.startDate,drag.endDate)-1,delta))})};const up=()=>{const p=previewRef.current;if(p){onUpdateTask(p.id,{startDate:p.startDate,endDate:p.endDate,duration:Math.max(1,dateDiff(p.startDate,p.endDate)+1)});onSelect(p.id)}setDrag(null);setPreview(null)};window.addEventListener('pointermove',move);window.addEventListener('pointerup',up,{once:true});return()=>{window.removeEventListener('pointermove',move);window.removeEventListener('pointerup',up)}},[drag,onSelect,onUpdateTask])
  const beginDrag=(event:React.PointerEvent,task:Task,mode:'move'|'resize')=>{if(task.isLocked)return;event.preventDefault();event.stopPropagation();onSelect(task.id);setDrag({id:task.id,mode,startX:event.clientX,pxPerDay,startDate:task.startDate,endDate:task.endDate});setPreview({id:task.id,startDate:task.startDate,endDate:task.endDate})}
  return <div className="gantt-layout"><section className="panel gantt-panel"><div className="panel-toolbar"><div><button disabled={!canUndo} onClick={onUndo}>↶</button><button disabled={!canRedo} onClick={onRedo}>↷</button><button title="按依赖关系重算" onClick={onRecalculate}>⟳</button><span>时间尺度</span>{([['day','日'],['week','周'],['month','月']] as const).map(([k,l])=><button className={scale===k?'active':''} onClick={()=>setScale(k)} key={k}>{l}</button>)}</div><span>{start} 至 {end} · {baseline?'灰色细条为基准计划 · ':''}拖动条块调整日期，拖动右端调整工期</span></div><div className={`gantt-table ${drag?'dragging':''}`}><div className="gantt-header" style={{gridTemplateColumns:columns}}><b>任务</b><b>工期</b><b>计划时间轴</b></div>{tasks.map(t=>{const view=preview?.id===t.id?preview:t,left=dateDiff(start,view.startDate)*pxPerDay,width=Math.max(pxPerDay,dateDiff(view.startDate,view.endDate)*pxPerDay+pxPerDay),base=baseline?.tasks.find(x=>x.id===t.id),baseLeft=base?dateDiff(start,base.startDate)*pxPerDay:0,baseWidth=base?Math.max(pxPerDay,dateDiff(base.startDate,base.endDate)*pxPerDay+pxPerDay):0;return <div className={`gantt-row ${selectedId===t.id?'selected':''}`} style={{gridTemplateColumns:columns}} key={t.id} onClick={()=>onSelect(t.id)}><div><b>{t.wbsCode} {t.name}</b><small>{t.phase}{t.isLocked?' · 锁定节点':''}{base&&dateDiff(base.endDate,t.endDate)!==0?` · 基准偏差 ${dateDiff(base.endDate,t.endDate)>0?'+':''}${dateDiff(base.endDate,t.endDate)}d`:''}</small></div><span>{Math.max(1,dateDiff(view.startDate,view.endDate)+1)}d</span><div className="bar-track" style={{backgroundSize:`${pxPerDay*(scale==='day'?1:scale==='week'?7:30)}px 100%`}}>{base&&<span className="baseline-bar" style={{left:baseLeft,width:baseWidth}}/>}<i aria-label={`${t.name}计划条`} className={`${t.isCritical?'critical':''} ${t.isLocked?'locked':''}`} onPointerDown={e=>beginDrag(e,t,'move')} style={{left,width,background:PHASE_COLORS[t.phase]}}>{width>85?t.name:''}{!t.isLocked&&<span aria-label={`${t.name}调整工期`} onPointerDown={e=>beginDrag(e,t,'resize')}/>}</i></div></div>})}</div></section>{selected&&<TaskEditor task={selected} tasks={tasks} logicMessage={logicMessage} onUpdate={p=>onUpdateTask(selected.id,p)} onUpdateLogic={p=>onUpdateLogic(selected.id,p)}/>}</div>
}

const taskSpaceLabel=(task:Task)=>task.spacePath?Object.entries(task.spacePath).map(([key,value])=>`${key}：${value}`).join(' / '):[task.building,task.floor,task.workArea].filter(Boolean).join(' / ')
const taskLogicLabel=(task:Task)=>taskDependencies(task).map(edge=>`${edge.relationType}${edge.lag===0?'':edge.lag>0?`+${edge.lag}`:edge.lag}`).join(' / ')||'-'

function DependencyEditor({task,tasks,onUpdate}:{task:Task,tasks:Task[],onUpdate:(p:Partial<Task>)=>void}){
  const edges=taskDependencies(task)
  const commit=(next:TaskDependency[])=>onUpdate({
    dependencies:next,
    predecessors:next.map(edge=>edge.predecessorId),
    relationType:next[0]?.relationType??task.relationType,
    lag:next[0]?.lag??task.lag,
  })
  const update=(index:number,patch:Partial<TaskDependency>)=>commit(edges.map((edge,i)=>i===index?{...edge,...patch}:edge).filter((edge,i,all)=>all.findIndex(item=>item.predecessorId===edge.predecessorId)===i))
  const downstream=new Set([task.id])
  let changed=true
  while(changed){changed=false;tasks.forEach(candidate=>{if(!downstream.has(candidate.id)&&taskDependencies(candidate).some(edge=>downstream.has(edge.predecessorId))){downstream.add(candidate.id);changed=true}})}
  const available=tasks.filter(candidate=>!downstream.has(candidate.id)&&!edges.some(edge=>edge.predecessorId===candidate.id))
  return <div className="dependency-editor"><div className="dependency-head"><b>逻辑关系（逐条依赖）</b><button className="btn" disabled={!available.length} onClick={()=>commit([...edges,{predecessorId:available[0].id,relationType:'FS',lag:0}])}>＋ 添加前置</button></div>{edges.length?edges.map((edge,index)=><div className="dependency-row" key={`${edge.predecessorId}-${index}`}><label>前置任务<select aria-label={`前置任务 ${index+1}`} value={edge.predecessorId} onChange={e=>update(index,{predecessorId:e.target.value})}>{tasks.filter(candidate=>candidate.id!==task.id&&(!downstream.has(candidate.id)||candidate.id===edge.predecessorId)).map(candidate=><option value={candidate.id} key={candidate.id}>{candidate.wbsCode} {candidate.name}</option>)}</select></label><label>关系<select aria-label={`关系 ${index+1}`} value={edge.relationType} onChange={e=>update(index,{relationType:e.target.value as RelationType})}>{['FS','SS','FF','SF'].map(value=><option key={value}>{value}</option>)}</select></label><label>Lag<input aria-label={`Lag ${index+1}`} type="number" value={edge.lag} onChange={e=>update(index,{lag:Number(e.target.value)})}/><span>天</span></label><button className="dependency-remove" aria-label={`删除依赖 ${index+1}`} onClick={()=>commit(edges.filter((_,i)=>i!==index))}>×</button></div>):<p className="dependency-empty">当前为无前置任务，可作为计划起点。</p>}</div>
}

function TaskEditor({task,tasks,logicMessage,onUpdate,onUpdateLogic}:{task:Task,tasks:Task[],logicMessage:string,onUpdate:(p:Partial<Task>)=>void,onUpdateLogic:(p:Partial<Task>)=>void}){
  const space=taskSpaceLabel(task)
  return <aside className="panel task-editor"><SectionTitle title="任务调整" text={`${task.wbsCode} ${task.name}`}/>{space&&<div className="task-location"><b>{space}</b><small>空间与工作面</small></div>}<TextField label="计划开始" type="date" value={task.startDate} onChange={v=>onUpdate({startDate:v})}/><TextField label="计划完成" type="date" value={task.endDate} onChange={v=>onUpdate({endDate:v,duration:Math.max(1,dateDiff(task.startDate,v)+1)})}/><DependencyEditor task={task} tasks={tasks} onUpdate={onUpdateLogic}/>{logicMessage&&<p className={`logic-message ${logicMessage.includes('循环')||logicMessage.includes('无法')||logicMessage.includes('失败')?'error':''}`}>{logicMessage}</p>}<SelectField label="状态" value={task.status} options={['未开始','施工中','实体完成','自检完成','监理验收通过','移交下道工序','资料闭合','暂停','延期']} onChange={v=>onUpdate({status:v as TaskStatus})}/><NumberField label="完成进度" value={task.progress} onChange={v=>onUpdate({progress:Math.min(100,Math.max(0,v))})} suffix="%"/><TextField label="实际开始" type="date" value={task.actualStartDate??''} onChange={v=>onUpdate({actualStartDate:v})}/><TextField label="实际完成" type="date" value={task.actualEndDate??''} onChange={v=>onUpdate({actualEndDate:v,progress:v?100:task.progress,status:v?'移交下道工序':task.status})}/>{task.quantity!==undefined&&<NumberField label="工程量" value={task.quantity} onChange={v=>onUpdate({quantity:Math.max(0,v)})} suffix={task.unit??''}/>}<TextField label="资源投入" value={task.resourceDemand?.join('、')??''} onChange={v=>onUpdate({resourceDemand:v.split(/[、,，;]/).map(x=>x.trim()).filter(Boolean)})}/><TextField label="材料节点" value={task.materialNodes?.join('、')??''} onChange={v=>onUpdate({materialNodes:v.split(/[、,，;]/).map(x=>x.trim()).filter(Boolean)})}/><div className="task-badges"><span>{task.isCritical?'关键路径':'非关键'}</span><span>总时差 {task.totalFloat} 天</span><span>{task.source}</span><span>{task.compressibility}</span></div></aside>
}

function Network({tasks}:{tasks:Task[]}){const levels=new Map<string,number>();tasks.forEach(t=>levels.set(t.id,t.predecessors.length?Math.max(...t.predecessors.map(p=>levels.get(p)??0))+1:0));const groups=[...new Set(levels.values())].map(l=>tasks.filter(t=>levels.get(t.id)===l));return <section className="panel network"><SectionTitle title="单代号网络图 AON" text="节点显示 ES/EF、逐边逻辑关系和关键路径"/><div className="network-canvas">{groups.map((group,i)=><div className="network-column" key={i}>{group.map(t=><div className={`network-node ${t.isCritical?'critical':''}`} key={t.id}><small>{t.wbsCode} · {taskLogicLabel(t)}</small><b>{t.name}</b><span>{t.startDate.slice(5)} → {t.endDate.slice(5)}</span>{i<groups.length-1&&<i>→</i>}</div>)}</div>)}</div></section>}

function Wbs({tasks,onSelect}:{tasks:Task[],onSelect:(id:string)=>void}){const names=new Map(tasks.map(task=>[task.id,task.name]));return <section className="panel table-panel"><SectionTitle title="WBS 分解表" text="逐行复核空间、工作面、工程量、逐边依赖和责任口径"/><table><thead><tr><th>WBS</th><th>任务名称</th><th>空间/工作面</th><th>工程量</th><th>阶段</th><th>工期</th><th>计划时间</th><th>前置任务</th><th>逻辑</th><th>状态</th><th>材料节点</th><th>责任单位</th></tr></thead><tbody>{tasks.map(t=><tr key={t.id} onClick={()=>onSelect(t.id)}><td>{t.wbsCode}</td><td><b>{t.name}</b>{t.isCritical&&<em>关键</em>}</td><td>{taskSpaceLabel(t)||'-'}</td><td>{t.quantity!==undefined?`${t.quantity} ${t.unit??''}`:'-'}</td><td>{t.phase}</td><td>{t.duration} 天</td><td>{t.startDate}<br/>{t.endDate}</td><td>{taskDependencies(t).map(edge=>names.get(edge.predecessorId)??edge.predecessorId).join('、')||'-'}</td><td>{taskLogicLabel(t)}</td><td>{t.status}</td><td>{t.materialNodes?.join('、')||'-'}</td><td>{t.responsibleParty}</td></tr>)}</tbody></table></section>}

function Process({tasks,selected,onSelect,onUpdate,onInsert}:{tasks:Task[],selected:Task,onSelect:(id:string)=>void,onUpdate:(p:Partial<Task>)=>void,onInsert:(name?:string)=>void}){return <div className="process-layout"><section className="panel process-list"><SectionTitle title="工序管理" text="按施工工序查看专业、空间、依赖与前置条件"/>{tasks.map(t=><button className={selected.id===t.id?'active':''} key={t.id} onClick={()=>onSelect(t.id)}><span style={{background:PHASE_COLORS[t.phase]}}/><div><b>{t.name}</b><small>{t.discipline} · {taskSpaceLabel(t)||'全项目'} · {t.duration} 天 · {t.status}</small></div><i>{t.isCritical?'关键':''}</i></button>)}</section><aside className="panel process-detail"><h2>{selected.name}</h2><p>{selected.generationBasis}</p><div className="summary-cards"><Metric label="工期" value={`${selected.duration}天`}/><Metric label="总时差" value={`${selected.totalFloat}天`}/><Metric label="工作面" value={taskSpaceLabel(selected)||'全项目'}/><Metric label="工程量" value={selected.quantity!==undefined?`${selected.quantity}${selected.unit??''}`:'-'}/></div>{selected.resourceDemand?.length?<><h3>资源投入</h3><p className="detail-tags">{selected.resourceDemand.map(x=><span key={x}>{x}</span>)}</p></>:null}{selected.materialNodes?.length?<><h3>材料节点</h3><p className="detail-tags">{selected.materialNodes.map(x=><span key={x}>{x}</span>)}</p></>:null}<h3>前置条件</h3>{selected.startConditions.length?selected.startConditions.map(c=><label className="condition" key={c.id}><input type="checkbox" checked={c.status==='已满足'} onChange={e=>onUpdate({startConditions:selected.startConditions.map(x=>x.id===c.id?{...x,status:e.target.checked?'已满足':'待确认'}:x)})}/><span><b>{c.name}</b><small>{c.type} · {c.strength}</small></span></label>):<p className="muted">无需额外前置条件。</p>}<button className="btn primary block" onClick={()=>onInsert()}>在当前任务后插入工序</button></aside></div>}

function Library({project,templates,customTemplates,templateSyncStatus,onCustomTemplatesChange,onInsert}:{project:ProjectData,templates:TaskTemplate[],customTemplates:TaskTemplate[],templateSyncStatus:string,onCustomTemplatesChange:(v:TaskTemplate[])=>void,onInsert:(template:TaskTemplate)=>void}){
  const [search,setSearch]=useState(''),[draft,setDraft]=useState<TaskTemplate|null>(null),[message,setMessage]=useState('')
  const items=templates.filter(t=>`${t.name}${t.phase}${t.discipline}${t.expansionDimensions?.join('')}`.includes(search))
  const blank=():TaskTemplate=>({id:'',name:'',phase:'自定义阶段',discipline:'自定义专业',duration:5,predecessorNames:[],relationType:'FS',lag:0,compressibility:'部分可压缩',responsibleParty:'总包单位',projectType:project.projectType,expansionDimensions:[],quantityUnit:'项',resourceDemand:[],materialNodes:[],isCustom:true})
  const save=()=>{if(!draft?.name.trim()){setMessage('请填写模板名称。');return}const record={...draft,id:draft.id||`CUSTOM-${Date.now()}`,name:draft.name.trim(),isCustom:true,version:draft.id?(draft.version??1)+1:1,updatedAt:new Date().toISOString()};onCustomTemplatesChange([...customTemplates.filter(t=>t.id!==record.id),record]);setDraft(null);setMessage(`已保存自定义模板“${record.name}” V${record.version}，新生成的计划会自动使用。`)}
  const remove=(template:TaskTemplate)=>{if(!window.confirm(`确定删除自定义模板“${template.name}”吗？`))return;onCustomTemplatesChange(customTemplates.filter(t=>t.id!==template.id));setMessage(`已删除“${template.name}”。`)}
  const copy=(template:TaskTemplate)=>setDraft({...template,id:'',name:`${template.name}（自定义）`,projectType:project.projectType,isCustom:true})
  return <section className="panel library"><div className="library-head"><SectionTitle title={`${project.projectType}工序库`} text={`${templates.length} 项当前可用模板，其中 ${templates.filter(t=>t.isCustom).length} 项为自定义模板 · ${templateSyncStatus}`}/><div><input placeholder="搜索工序、阶段、专业或空间维度" value={search} onChange={e=>setSearch(e.target.value)}/><button className="btn primary" onClick={()=>setDraft(blank())}>＋ 新增自定义模板</button></div></div>{message&&<p className="library-message">{message}</p>}{draft&&<div className="template-editor"><div className="template-editor-head"><div><h3>{draft.id?'编辑自定义模板':'新增自定义模板'}</h3><p>模板保存后会进入当前用户的后端模板库，并参与后续计划生成。</p></div><button onClick={()=>setDraft(null)}>×</button></div><div className="fields"><TextField label="工序名称" value={draft.name} onChange={v=>setDraft({...draft,name:v})} wide/><TextField label="阶段" value={draft.phase} onChange={v=>setDraft({...draft,phase:v})}/><TextField label="专业" value={draft.discipline} onChange={v=>setDraft({...draft,discipline:v})}/><NumberField label="默认工期" value={draft.duration} onChange={v=>setDraft({...draft,duration:Math.max(1,v)})} suffix="天"/><SelectField label="适用项目" value={draft.projectType??project.projectType} options={[...PROJECT_TYPES,'通用']} onChange={v=>setDraft({...draft,projectType:v as ProjectType|'通用'})}/><SelectField label="逻辑关系" value={draft.relationType} options={['FS','SS','FF','SF']} onChange={v=>setDraft({...draft,relationType:v as TaskTemplate['relationType']})}/><NumberField label="Lag" value={draft.lag} onChange={v=>setDraft({...draft,lag:v})} suffix="天"/><TextField label="计量单位" value={draft.quantityUnit??'项'} onChange={v=>setDraft({...draft,quantityUnit:v})}/><TextField label="责任单位" value={draft.responsibleParty} onChange={v=>setDraft({...draft,responsibleParty:v})}/><TextField label="前置工序名称" value={draft.predecessorNames.join('、')} onChange={v=>setDraft({...draft,predecessorNames:v.split(/[、,，;]/).map(x=>x.trim()).filter(Boolean)})} wide/><TextField label="资源投入" value={draft.resourceDemand?.join('、')??''} onChange={v=>setDraft({...draft,resourceDemand:v.split(/[、,，;]/).map(x=>x.trim()).filter(Boolean)})} wide/><TextField label="材料节点" value={draft.materialNodes?.join('、')??''} onChange={v=>setDraft({...draft,materialNodes:v.split(/[、,，;]/).map(x=>x.trim()).filter(Boolean)})} wide/></div><div className="template-dimensions"><b>空间展开维度</b><p>未选择时每个项目只生成一项；选择后按空间取值组合批量展开。</p><div className="checks">{(project.spatialDimensions??[]).map(d=><label key={d.id}><input type="checkbox" checked={draft.expansionDimensions?.includes(d.name)??false} onChange={e=>setDraft({...draft,expansionDimensions:e.target.checked?[...(draft.expansionDimensions??[]),d.name]:(draft.expansionDimensions??[]).filter(x=>x!==d.name)})}/>{d.name}（{d.values.length}）</label>)}</div></div><div className="button-row"><button className="btn" onClick={()=>setDraft(null)}>取消</button><button className="btn primary" onClick={save}>保存模板</button></div></div>}<div className="library-grid">{items.map(t=><article className={t.isCustom?'custom-template':''} key={t.id}><span>{t.isCustom?'自定义':t.id}</span><h3>{t.name}</h3><p>{t.phase} · {t.discipline}</p><dl><dt>默认工期</dt><dd>{t.duration} 天</dd><dt>默认关系</dt><dd>{t.relationType}+{t.lag}</dd><dt>空间展开</dt><dd>{t.expansionDimensions?.join(' × ')||'不展开'}</dd><dt>计量单位</dt><dd>{t.quantityUnit??'项'}</dd></dl><div className="template-actions"><button className="btn primary" onClick={()=>onInsert(t)}>插入计划</button>{t.isCustom?<><button className="btn" onClick={()=>setDraft({...t})}>编辑</button><button className="btn danger" onClick={()=>remove(t)}>删除</button></>:<button className="btn" onClick={()=>copy(t)}>复制修改</button>}</div></article>)}</div></section>
}

function Resources({project,tasks,notice,onCapacityChange,onLevel}:{project:ProjectData,tasks:Task[],notice:string,onCapacityChange:(resource:string,capacity:number)=>void,onLevel:()=>void}){const loads=useMemo(()=>analyzeResourceLoad(project,tasks),[project,tasks]);const conflicts=loads.filter(x=>x.peak>x.capacity);return <section className="panel resources"><div className="resource-title"><SectionTitle title="资源负荷与并行冲突" text="按有效施工日扫描专业班组和设备并行占用；容量可直接调整，自动错峰会顺延所选任务及其后续链。"/><button className="btn primary" disabled={!conflicts.length} onClick={onLevel}>自动错峰</button></div><div className="resource-summary"><Metric label="资源池" value={loads.length}/><Metric label="冲突资源" value={conflicts.length}/><Metric label="超载天数" value={loads.reduce((n,x)=>n+x.overloadedDays,0)}/><Metric label="最高负荷" value={loads.length?Math.max(...loads.map(x=>x.peak)):'-'}/></div><div className="resource-table"><div className="resource-head"><b>资源池</b><b>容量</b><b>峰值</b><b>负荷</b><b>峰值日期与任务</b></div>{loads.map(load=>{const ratio=Math.min(100,load.peak/Math.max(1,load.capacity)*100),over=load.peak>load.capacity;return <div className={`resource-row ${over?'overload':''}`} key={load.resource}><b>{load.resource}</b><span><input aria-label={`${load.resource}容量`} type="number" min="1" value={load.capacity} onChange={e=>onCapacityChange(load.resource,Number(e.target.value))}/></span><span>{load.peak}</span><div><i style={{width:`${ratio}%`}}/><em>{Math.round(load.peak/load.capacity*100)}%</em></div><p><strong>{load.peakDate||'-'}</strong><small>{load.activeTasks.join('、')||'无任务'}{over&&` · 超载 ${load.overloadedDays} 天`}</small></p></div>})}</div>{(conflicts.length>0||notice)&&<div className="resource-advice"><b>{conflicts.length?'可执行处理':'处理结果'}</b><p>{notice||'点击“自动错峰”将优先顺延非关键且不连接锁定节点的任务；也可以直接提高对应资源容量。所有错峰操作均可撤销。'}</p></div>}</section>}

function Review({risks,tasks}:{risks:ReviewItem[],tasks:Task[]}){const health=Math.max(35,100-risks.filter(r=>r.level==='高').length*15-risks.filter(r=>r.level==='中').length*6);return <div className="review-layout"><section className="panel"><SectionTitle title="计划健康度" text="基于关键路径、逻辑冲突和假设完整度"/><div className="health"><strong>{health}</strong><span>/100</span><i style={{width:`${health}%`}}/></div><div className="summary-cards"><Metric label="计划任务" value={tasks.length}/><Metric label="关键任务" value={tasks.filter(t=>t.isCritical).length}/><Metric label="高风险" value={risks.filter(r=>r.level==='高').length}/></div></section><section className="panel risk-panel"><SectionTitle title="风险概览" text="集中检查工期、采购、验收和前置条件"/>{risks.length?risks.map(r=><article key={r.id}><b className={`level ${r.level}`}>{r.level}</b><div><h3>{r.title}</h3><p>{r.impact}</p><small>建议：{r.suggestion}</small></div><span>{r.category}</span></article>):<div className="empty">当前计划未发现高优先级风险。</div>}</section></div>}

function Milestones({tasks}:{tasks:Task[]}){return <section className="panel milestones"><SectionTitle title="关键节点总控" text="锁定合同与管理节点，判断实际偏差影响"/><div className="milestone-line">{tasks.filter(t=>t.isMilestone).map((t,i)=><article key={t.id}><span>{i+1}</span><div><small>{t.isLocked?'锁定节点':'管理节点'}</small><h3>{t.name}</h3><b>{t.endDate}</b><p>{t.status}</p></div></article>)}</div></section>}

function Report({project,tasks,risks,settings}:{project:ProjectData,tasks:Task[],risks:ReviewItem[],settings:AiSettings|null}){const [aiText,setAiText]=useState(''),[loading,setLoading]=useState(false);const generate=async()=>{if(!settings){setAiText('未配置 API Key。以下本地摘要可直接用于项目会。');return}setLoading(true);try{setAiText(await explainSchedule('生成项目会汇报摘要，包含总体进展、关键线路、三项风险和下周动作。',project,tasks,settings))}catch(e){setAiText(e instanceof Error?e.message:'生成失败')}finally{setLoading(false)}};return <section className="panel report"><div className="report-title"><div><small>汇报版工程总进度计划</small><h1>{project.projectName}</h1><p>{project.location} · {project.projectType} · {project.spatialDimensions?.map(d=>`${d.name}${d.values.length}项`).join(' / ')}</p></div><button className="btn primary" onClick={generate} disabled={loading}>{loading?'生成中…':'AI 生成汇报口径'}</button></div><div className="report-metrics"><Metric label="计划开工" value={project.startDate}/><Metric label="当前完工" value={tasks.at(-1)?.endDate??'-'}/><Metric label="关键任务" value={tasks.filter(t=>t.isCritical).length}/><Metric label="高风险" value={risks.filter(r=>r.level==='高').length}/></div><div className="report-grid"><div><h2>关键线路摘要</h2><p>{tasks.filter(t=>t.isCritical&&!t.isMilestone).map(t=>t.name).join(' → ')}</p><h2>AI / 项目会摘要</h2><pre>{aiText||'当前版本由本地规则引擎生成。建议项目会优先确认锁定节点、关键作业面、长周期材料设备和专项验收计划。'}</pre></div><div><h2>主要风险</h2>{risks.slice(0,5).map((r,i)=><p key={r.id}><b>{i+1}. {r.title}</b><br/><span>{r.suggestion}</span></p>)}</div></div></section>}
